#include "router_ux_engine.h"
#include <iomanip>
#include <sstream>
#include <algorithm>
#include <numeric>

namespace RawrXD {

// =============================================================================
// "Why This Backend?" Explanation Engine
// =============================================================================

std::string RouterUXEngine::explainRoutingDecision(const RoutingDecision& decision) {
    std::stringstream ss;
    ss << "{\n";
    ss << "  \"selectedBackend\": \"" << decision.backendName << "\",\n";
    ss << "  \"confidence\": " << std::fixed << std::setprecision(2) << decision.confidence << ",\n";
    ss << "  \"explanation\": {\n";
    
    // Factor breakdown
    ss << "    \"factors\": [\n";
    for (size_t i = 0; i < decision.factors.size(); ++i) {
        const auto& f = decision.factors[i];
        ss << "      {\"" << f.name << "\": " << f.score 
           << ", \"weight\": " << f.weight << "}";
        if (i < decision.factors.size() - 1) ss << ",";
        ss << "\n";
    }
    ss << "    ],\n";
    
    // Capability snapshot
    auto* backend = registry_->getBackend(decision.backendName);
    ss << "    \"capabilitySnapshot\": {\n";
    ss << "      \"maxTokens\": " << backend->maxTokens << ",\n";
    ss << "      \"supportsStreaming\": " << (backend->capabilities & CAP_STREAMING ? "true" : "false") << ",\n";
    ss << "      \"quantization\": \"" << getQuantizationString(backend->preferredQuant) << "\",\n";
    ss << "      \"currentLoad\": " << backend->currentLoad << ",\n";
    ss << "      \"avgLatencyMs\": " << backend->latencyStats.avg << "\n";
    ss << "    },\n";
    
    // Pin status
    auto pinIt = pinnedTasks_.find(decision.taskHash);
    if (pinIt != pinnedTasks_.end()) {
        ss << "    \"pinStatus\": \"PINNED to " << pinIt->second << " (100% confidence override)\",\n";
    } else {
        ss << "    \"pinStatus\": \"unpinned (policy-driven)\",\n";
    }
    
    // Latency breakdown
    ss << "    \"latencyBreakdown\": {\n";
    ss << "      \"routingDecisionUs\": " << decision.timing.decisionTimeUs << ",\n";
    ss << "      \"modelLoadMs\": " << decision.timing.modelLoadMs << ",\n";
    ss << "      \"firstTokenMs\": " << decision.timing.firstTokenMs << ",\n";
    ss << "      \"totalEstimatedMs\": " << (decision.timing.modelLoadMs + decision.timing.firstTokenMs) << "\n";
    ss << "    }\n";
    ss << "  }\n}";
    
    return ss.str();
}

// =============================================================================
// Task Pinning System (Override Router)
// =============================================================================

bool RouterUXEngine::pinTaskToBackend(uint64_t taskHash, const std::string& backendName) {
    std::lock_guard<std::mutex> lock(pinMutex_);
    
    auto* backend = registry_->getBackend(backendName);
    if (!backend) return false;
    
    pinnedTasks_[taskHash] = backendName;
    pinMetadata_[taskHash] = {
        .timestamp = getTimestamp(),
        .reason = "User override",
        .expiresAt = 0 // Never expires unless unpinned
    };
    
    return true;
}

bool RouterUXEngine::unpinTask(uint64_t taskHash) {
    std::lock_guard<std::mutex> lock(pinMutex_);
    auto it = pinnedTasks_.find(taskHash);
    if (it == pinnedTasks_.end()) return false;
    
    pinnedTasks_.erase(it);
    pinMetadata_.erase(taskHash);
    return true;
}

std::optional<std::string> RouterUXEngine::getPinnedBackend(uint64_t taskHash) {
    std::lock_guard<std::mutex> lock(pinMutex_);
    auto it = pinnedTasks_.find(taskHash);
    if (it != pinnedTasks_.end()) {
        return it->second;
    }
    return std::nullopt;
}

json RouterUXEngine::getAllPins() {
    std::lock_guard<std::mutex> lock(pinMutex_);
    json pins = json::array();
    
    for (const auto& [hash, backend] : pinnedTasks_) {
        const auto& meta = pinMetadata_[hash];
        pins.push_back({
            {"taskHash", hash},
            {"backend", backend},
            {"pinnedAt", meta.timestamp},
            {"reason", meta.reason}
        });
    }
    
    return pins;
}

// =============================================================================
// Cost/Latency Heatmap Engine
// =============================================================================

void RouterUXEngine::recordLatencySample(const std::string& backend, 
                                          const std::string& taskType,
                                          uint64_t latencyUs,
                                          bool success) {
    std::lock_guard<std::mutex> lock(heatmapMutex_);
    
    auto& cell = heatmap_[backend][taskType];
    cell.totalRequests++;
    if (success) cell.successfulRequests++;
    
    // Rolling average with exponential decay
    const double alpha = 0.3; // New sample weight
    cell.avgLatencyUs = (alpha * latencyUs) + ((1.0 - alpha) * cell.avgLatencyUs);
    cell.minLatencyUs = std::min(cell.minLatencyUs, latencyUs);
    cell.maxLatencyUs = std::max(cell.maxLatencyUs, latencyUs);
    
    // Cost tier estimation (simplified model)
    cell.estimatedCostPer1K = estimateCost(backend, taskType, cell.avgLatencyUs);
}

json RouterUXEngine::generateHeatmap() {
    std::lock_guard<std::mutex> lock(heatmapMutex_);
    
    json result;
    result["backends"] = json::array();
    result["taskTypes"] = {"code_completion", "chat", "agent_action", "refactor", "explain"};
    result["grid"] = json::array();
    
    for (const auto& [backend, tasks] : heatmap_) {
        json backendRow;
        backendRow["backend"] = backend;
        backendRow["cells"] = json::array();
        
        for (const auto& [task, data] : tasks) {
            json cell;
            cell["task"] = task;
            cell["avgMs"] = data.avgLatencyUs / 1000.0;
            cell["minMs"] = data.minLatencyUs / 1000.0;
            cell["maxMs"] = data.maxLatencyUs / 1000.0;
            cell["requests"] = data.totalRequests;
            cell["successRate"] = data.totalRequests > 0 ? 
                (double)data.successfulRequests / data.totalRequests : 0.0;
            cell["costTier"] = data.estimatedCostPer1K;
            
            // Color coding based on latency percentiles
            double p95 = data.avgLatencyUs * 1.5; // Estimated
            if (p95 < 50000) cell["heat"] = "green";      // <50ms
            else if (p95 < 200000) cell["heat"] = "yellow"; // <200ms
            else if (p95 < 1000000) cell["heat"] = "orange";// <1s
            else cell["heat"] = "red";                     // >1s
            
            backendRow["cells"].push_back(cell);
        }
        
        result["grid"].push_back(backendRow);
    }
    
    return result;
}

// =============================================================================
// Ensemble Routing (Research Track)
// =============================================================================

EnsembleResult RouterUXEngine::routeEnsemble(const TaskRequest& request,
                                              const std::vector<std::string>& candidateBackends) {
    EnsembleResult result;
    result.requestId = generateUUID();
    
    if (!ensembleEnabled_) {
        result.status = "disabled";
        return result;
    }
    
    // Fan-out to all viable backends concurrently
    std::vector<std::future<BackendResponse>> futures;
    
    for (const auto& backendName : candidateBackends) {
        auto* backend = registry_->getBackend(backendName);
        if (!backend || !backend->isHealthy()) continue;
        
        futures.push_back(std::async(std::launch::async, [&, backendName]() {
            auto start = high_resolution_clock::now();
            
            // Send identical request to this backend
            auto response = backend->sendRequest(request);
            
            auto end = high_resolution_clock::now();
            auto duration = duration_cast<microseconds>(end - start).count();
            
            return BackendResponse{
                .backendName = backendName,
                .response = response,
                .latencyUs = duration,
                .confidence = calculateConfidence(response, request)
            };
        }));
    }
    
    // Collect results with timeout
    std::vector<BackendResponse> responses;
    for (auto& future : futures) {
        if (future.wait_for(seconds(30)) == std::future_status::ready) {
            responses.push_back(future.get());
        }
    }
    
    if (responses.empty()) {
        result.status = "all_backends_failed";
        return result;
    }
    
    // Confidence-weighted selection algorithm
    double totalWeight = 0.0;
    for (const auto& resp : responses) {
        double weight = resp.confidence / std::max(1.0, (double)resp.latencyUs / 1000000.0); // Confidence per second
        result.weights[resp.backendName] = weight;
        totalWeight += weight;
    }
    
    // Normalize and select winner
    std::string winner;
    double maxWeight = 0.0;
    for (auto& [name, weight] : result.weights) {
        weight /= totalWeight; // Normalize
        if (weight > maxWeight) {
            maxWeight = weight;
            winner = name;
        }
    }
    
    result.winner = winner;
    result.allResponses = responses;
    result.status = "success";
    
    // Log for analysis
    logEnsembleResult(result);
    
    return result;
}

// =============================================================================
// Offline Routing Simulation
// =============================================================================

SimulationResult RouterUXEngine::simulateRouting(const std::vector<HistoricalTask>& history,
                                                  const RoutingPolicy& policy) {
    SimulationResult result;
    result.totalTasks = history.size();
    
    std::map<std::string, int> backendUsage;
    std::vector<double> accuracyScores;
    
    for (const auto& task : history) {
        // Replay through current router with given policy
        auto decision = router_->routeWithPolicy(task.request, policy);
        
        // Compare to optimal (which we know from historical outcome)
        bool correct = (decision.backendName == task.optimalBackend);
        result.correctPredictions += correct ? 1 : 0;
        
        backendUsage[decision.backendName]++;
        
        // Calculate confidence accuracy (did high confidence = correct?)
        if (decision.confidence > 0.8) {
            result.highConfidenceCount++;
            if (correct) result.highConfidenceAccuracy++;
        }
        
        // Cost calculation
        result.totalEstimatedCost += estimateCost(decision.backendName, task.request);
    }
    
    result.accuracy = (double)result.correctPredictions / result.totalTasks;
    result.avgConfidence = result.highConfidenceCount > 0 ? 
        (double)result.highConfidenceAccuracy / result.highConfidenceCount : 0.0;
    
    // Backend distribution analysis
    for (const auto& [backend, count] : backendUsage) {
        result.backendDistribution[backend] = (double)count / result.totalTasks;
    }
    
    return result;
}

// =============================================================================
// Command Handlers (Wire to your IDM_ROUTER_* handlers)
// =============================================================================

void RouterUXEngine::handleCommandWhyBackend(HWND hwnd) {
    auto* router = Router::instance();
    auto lastDecision = router->getLastDecision();
    
    std::string explanation = explainRoutingDecision(lastDecision);
    
    // Show in dialog or copy to clipboard
    MessageBoxA(hwnd, explanation.c_str(), "Why This Backend?", MB_OK | MB_ICONINFORMATION);
    
    // Also POST to React panel
    postToReactPanel("/api/router/why", json::parse(explanation));
}

void RouterUXEngine::handleCommandPinTask(HWND hwnd) {
    // Get current task context from editor
    uint64_t taskHash = getCurrentTaskHash();
    std::string currentBackend = getCurrentBackend();
    
    if (pinTaskToBackend(taskHash, currentBackend)) {
        std::string msg = "Pinned task " + std::to_string(taskHash) + " to " + currentBackend;
        MessageBoxA(hwnd, msg.c_str(), "Task Pinned", MB_OK);
    }
}

void RouterUXEngine::handleCommandShowHeatmap(HWND hwnd) {
    json heatmap = generateHeatmap();
    
    // Render in custom window or send to React
    createHeatmapWindow(heatmap);
}

void RouterUXEngine::handleCommandToggleEnsemble(HWND hwnd) {
    ensembleEnabled_ = !ensembleEnabled_;
    std::string status = ensembleEnabled_ ? "ENABLED" : "DISABLED";
    MessageBoxA(hwnd, ("Ensemble routing " + status).c_str(), "Ensemble Toggle", MB_OK);
}

} // namespace RawrXD
