## MASM64 Optimized Hash for Task Identification
```asm
; router_hash.asm - FNV1a64 for task pinning
PUBLIC TaskHash_Compute

.code
TaskHash_Compute PROC FRAME
    ; RCX = ptr to task string, RDX = length
    ; Returns: RAX = hash (uint64)
    .endprolog
    
    push    rsi
    mov     rsi, rcx
    mov     rcx, rdx
    
    mov     rax, 14695981039346656037       ; FNV offset basis
    
@@loop:
    test    rcx, rcx
    jz      @@done
    
    movzx   rdx, byte ptr [rsi]
    xor     rax, rdx
    mov     rdx, 1099511628211              ; FNV prime
    mul     rdx                             ; RAX = RAX * RDX
    inc     rsi
    dec     rcx
    jmp     @@loop
    
@@done:
    pop     rsi
    ret
TaskHash_Compute ENDP

END
